import{_ as e,o as t,c as r,ag as l}from"./chunks/framework.C9sp7nFj.js";const b=JSON.parse('{"title":"授权码使用","description":"","frontmatter":{},"headers":[],"relativePath":"guide/help/license.md","filePath":"guide/help/license.md","lastUpdated":1780491682000}'),o={name:"guide/help/license.md"};function i(d,a,h,n,c,s){return t(),r("div",null,[...a[0]||(a[0]=[l('<h1 id="授权码使用" tabindex="-1">授权码使用 <a class="header-anchor" href="#授权码使用" aria-label="Permalink to &quot;授权码使用&quot;">​</a></h1><p>授权码用于激活 PanSave 系统。它是对捐助支持者的感谢回馈，首次登录后按页面提示填写即可。</p><h2 id="什么时候需要填写" tabindex="-1">什么时候需要填写 <a class="header-anchor" href="#什么时候需要填写" aria-label="Permalink to &quot;什么时候需要填写&quot;">​</a></h2><p>首次登录系统后，如果当前系统还没有授权，会自动进入“授权设置”页面。</p><p>你也可以在授权失效或需要重新填写时，按页面提示重新进入授权设置。</p><h2 id="使用步骤" tabindex="-1">使用步骤 <a class="header-anchor" href="#使用步骤" aria-label="Permalink to &quot;使用步骤&quot;">​</a></h2><ol><li>完成 Docker 部署并打开系统。</li><li>使用默认账号登录，首次登录后建议先修改用户名或密码。</li><li>按页面提示进入“授权设置”。</li><li>粘贴获得的授权码。</li><li>点击保存，等待页面提示授权结果。</li><li>授权通过后，侧边栏版本号旁会显示“已激活”。</li></ol><p>授权通过后，再继续配置 Telegram、网盘、TMDB、Emby、通知等功能。</p><h2 id="授权码从哪里获得" tabindex="-1">授权码从哪里获得 <a class="header-anchor" href="#授权码从哪里获得" aria-label="Permalink to &quot;授权码从哪里获得&quot;">​</a></h2><p>你可以通过 <a href="/donate">捐助支持</a> 获取授权码感谢回馈：</p><table tabindex="0"><thead><tr><th>捐助方式</th><th>感谢回馈</th></tr></thead><tbody><tr><td>捐助 50 元</td><td>永久授权码一枚</td></tr><tr><td>捐助 199 元</td><td>永久授权码一枚 + 3 天一对一远程部署指导</td></tr></tbody></table><p>这里的捐助用于鼓励开发和支持项目维护，授权码属于感谢回馈，不是软件售卖或资源服务。</p><h2 id="更换设备或重装时怎么办" tabindex="-1">更换设备或重装时怎么办 <a class="header-anchor" href="#更换设备或重装时怎么办" aria-label="Permalink to &quot;更换设备或重装时怎么办&quot;">​</a></h2><p>如果你要迁移到新机器，或重装 Docker 环境，建议先备份部署目录里的 <code>data</code> 文件夹。它保存了系统配置、登录状态和运行记录。</p><p>迁移时把 <code>data</code> 文件夹一起带到新环境，再启动 PanSave。这样可以尽量保留原有配置和授权状态。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="授权码填在哪里" tabindex="-1">授权码填在哪里 <a class="header-anchor" href="#授权码填在哪里" aria-label="Permalink to &quot;授权码填在哪里&quot;">​</a></h3><p>在 PanSave 的“授权设置”页面填写。正常使用时只需要在页面里粘贴授权码并保存。</p><h3 id="授权通过后还要配置什么" tabindex="-1">授权通过后还要配置什么 <a class="header-anchor" href="#授权通过后还要配置什么" aria-label="Permalink to &quot;授权通过后还要配置什么&quot;">​</a></h3><p>授权只代表系统可以正常使用，不会自动配置 Telegram、网盘、TMDB 或 Emby。后续仍需要按自己的使用场景完成基础配置。</p><h3 id="换机器后怎么办" tabindex="-1">换机器后怎么办 <a class="header-anchor" href="#换机器后怎么办" aria-label="Permalink to &quot;换机器后怎么办&quot;">​</a></h3><p>优先把原来的 <code>data</code> 文件夹整体迁移到新机器，再启动系统。如果没有迁移原数据，需要重新填写授权码并等待授权结果。</p><h3 id="保存授权码失败怎么办" tabindex="-1">保存授权码失败怎么办 <a class="header-anchor" href="#保存授权码失败怎么办" aria-label="Permalink to &quot;保存授权码失败怎么办&quot;">​</a></h3><p>先确认当前机器能正常访问互联网，并检查授权码是否复制完整。如果仍然失败，可以保留页面提示或截图，在 <a href="https://t.me/pansavechat" target="_blank" rel="noreferrer">Telegram 群组</a> 联系管理员排查。</p>',24)])])}const u=e(o,[["render",i]]);export{b as __pageData,u as default};
